// Define a class for transaction handling
class TransactionHandler {
    private let key = "my_secret_key"
    
    // Function to encrypt data using AES-256-GCM
    func encrypt(data: Data) -> Data? {
        do {
            let encryptedData = try AES.gcmEncrypt(data, withKey: key)
            return encryptedData
        } catch {
            print("Error encrypting data: \(error)")
            return nil
        }
    }
    
    // Function to decrypt data using AES-256-GCM
    func decrypt(encryptedData: Data) -> Data? {
        do {
            let decryptedData = try AES.gcmDecrypt(encryptedData, withKey: key)
            return decryptedData
        } catch {
            print("Error decrypting data: \(error)")
            return nil
        }
    }
    
    // Function to process a transaction and update the account balance
    func processTransaction(account: Account, amount: Double) -> (Account, Data?) {
        let encryptedAmount = encrypt(data: Data(bytes: [amount]))
        
        if let decryptedAmount = decrypt(encryptedData: encryptedAmount!) {
            var newBalance = account.balance + Double(decryptedAmount.bytes[0])
            
            // Update the account balance
            account.balance = newBalance
            
            return (account, nil)
        } else {
            print("Error processing transaction")
            return (account, nil)
        }
    }
}

